UPDATE plugin_manager
SET is_disabled = #{isDisabled}
WHERE jar_name = #{jarName}

UPDATE plugin_manager
SET plugin_version = #{version}
WHERE jar_name = #{jarName}

UPDATE plugin_manager
SET last_check = CURRENT_TIMESTAMP
WHERE jar_name = #{jarName}

UPDATE plugin_manager
SET update_url = #{updateUrl}
WHERE jar_name = #{jarName}
